var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"나는 아직 잘 모르겠어. 모건 할배.","JPN":"俺はまだよくわからない。モーガンのジジイ。","ENG":"Morgan, I still have no idea.","TWN":"我還不太明白，摩根老頭。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CHAIN","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"훗, 흥미롭군.","JPN":"なかなか興味深いな。","ENG":"Hah. Intriguing.","TWN":"呵，真有意思。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"제길, 또 끊어져 버렸어!","JPN":"くそ、また切れちまった！","ENG":"Dammit, it broke again!","TWN":"該死，又斷了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"할배가 물려줬던 사슬은 이 정도로 약하지 않았는데!","JPN":"ジジイにもらった鎖はこんなに弱くなかったのに！","ENG":"The chain that my grandfather left me wasn't this weak!","TWN":"爺爺傳給我的鐵鍊，我記得沒這麼脆弱啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"투덜거릴 여유 따위는 없어요, 물벼룩!","JPN":"愚痴ってる暇はありません、ミジンコ！","ENG":"There is no time to complain, Water Flea!","TWN":"你現在沒有時間發牢騷了，水蚤。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"우리 할아버지가 어떤 선택을 하려고 했는지.","JPN":"お爺さんがどんな選択をしようとしたのか。","ENG":"What would've my grandfather done?","TWN":"我爺爺會做出什麼選擇。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 나에게 정말로 프리드웬을 이어받을 자격이 있는지.","JPN":"それに俺が本当にプリドウェンを受け継ぐ資格があるのか。","ENG":"And am I really fit to succeed Prydwen?","TWN":"而我又是否真的有資格繼承普利多溫。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 당장 버넷 경만큼, 견고한 사슬을 만들어 내지 못하면.","JPN":"今すぐバーネット卿のものほど丈夫な鎖を生み出せないと。","ENG":"If you can't make chains as sturdy as Sir Burnett used to.","TWN":"如果你現在不能做出像伯內特卿的那般堅固的鐵鍊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"우리에게 승산은 없습니다.","JPN":"私たちに勝ち目はありません。","ENG":"There is no chance of us winning.","TWN":"那我們根本沒有勝算。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"제길, 알고 있다고!","JPN":"くそ、わかってるよ！","ENG":"Crap, I know!","TWN":"可惡，我知道！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"나는 여전히…… 잘 모르겠어.","JPN":"俺はいまだに……よくわからない。","ENG":"I'm still... not sure.","TWN":"我還是……不太明白。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"아직 무르지만, 제법 날카롭군.","JPN":"まだ未熟だが、なかなか鋭い。","ENG":"It's still weak, but quite sharp at the same time.","TWN":"雖然還很脆弱，但還蠻鋒利的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"사슬의 형태가 네놈에게 걸맞게 변화한 걸 보면.","JPN":"鎖の形が貴様に合わせて変化しているのを見ると。","ENG":"Seeing as how the form of the chain changes to fit you,","TWN":"鐵鍊的形體變得非常適合你。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"그 까다로운 방패가 네놈을 어느정도 주인으로 인정한 모양이야.","JPN":"あの気難しい盾が、貴様を主として少しは認めたようだ。","ENG":"perhaps that picky shield acknowledged you as its owner.","TWN":"看來那個挑剔的盾牌，在某種程度上認可了你。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"뭐라고?","JPN":"何だって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"하지만 아직 집념이 부족해!","JPN":"だが、まだ執念が足りない！","ENG":"But you're not desperate enough!","TWN":"但執念還不夠！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"크하아아악……!!","JPN":"ぐあああああっ！！","ENG":"Graah!!","TWN":"呃啊啊啊……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"로이 버넷……!!","JPN":"ロイ・バーネット……！！","ENG":"Roy Burnett...!!","TWN":"羅伊·伯內特……！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};